import { readFileSync } from 'node:fs';
import { Module } from '@nestjs/common';
import { WorkflowModule } from 'workflow/nest';
import { AppController } from './app.controller.js';

// Static readFileSync hint for @vercel/nft — ensures the manifest file
// generated by `workflow-nest build` is included in the Lambda bundle.
// Without this, NFT can't trace the dynamic path in WorkflowController.
// biome-ignore lint/correctness/noUnusedVariables: NFT hint
const _nftManifestHint = (() => {
  try {
    return readFileSync('.nestjs/workflow/manifest.json', 'utf-8');
  } catch {
    return null;
  }
})();

@Module({
  imports: [
    WorkflowModule.forRoot({
      skipBuild: !!process.env.VERCEL,
    }),
  ],
  controllers: [AppController],
})
export class AppModule {}
